// 이미 global에 config가 있으면 스킵
const existing = global.get('houseConfig');
if (existing) {
    node.warn('✅ houseConfig 이미 로드됨 (스킵)');
    node.status({ fill: 'green', shape: 'dot', text: 'config 이미 있음' });
    return null;
}

msg.topic = `SELECT config_json FROM config_cache ORDER BY version DESC LIMIT 1`;
return msg;

const rows = msg.payload || [];

if (rows.length > 0 && rows[0].config_json) {
    try {
        const config = JSON.parse(rows[0].config_json);
        global.set('houseConfig', config);

        const houseCount = config.houses ? config.houses.length : 0;
        node.warn(`📋 SQLite에서 config 복원 완료: ${houseCount}개 하우스`);
        node.status({ fill: 'green', shape: 'dot', text: `config 복원 (${houseCount} houses)` });
    } catch (e) {
        node.error('❌ config JSON 파싱 실패: ' + e.message);
        node.status({ fill: 'red', shape: 'dot', text: 'JSON 파싱 실패' });
    }
} else {
    node.warn('⚠️ SQLite config_cache 비어있음 - 서버 연결 시 자동 캐시됩니다');
    node.status({ fill: 'yellow', shape: 'ring', text: 'config 없음' });
}

return null;
